import React, { useState, useEffect, useRef } from "react";
import { supabase } from "../lib/supabase";
import { LOGO_B64 } from "../utils/logo";

const GREEN = "#22c55e";

export function CoachDashboard({ onExit }) {
  const [clients,    setClients]    = useState([]);
  const [loading,    setLoading]    = useState(true);
  const [uploading,  setUploading]  = useState(false);
  const [search,     setSearch]     = useState("");
  const [showAdd,    setShowAdd]    = useState(false);
  const [newEmail,   setNewEmail]   = useState("");
  const [newName,    setNewName]    = useState("");
  const [toast,      setToast]      = useState(null);
  const [selected,   setSelected]   = useState(null); // client sélectionné pour upload
  const fileRef = useRef();

  const showToast = (msg, type = "ok") => {
    setToast({ msg, type });
    setTimeout(() => setToast(null), 3000);
  };

  /* ── Charger clients ── */
  const loadClients = async () => {
    setLoading(true);
    const { data } = await supabase
      .from("clients")
      .select(`*, programmes(id, programme_name, uploaded_at, is_active)`)
      .order("created_at", { ascending: false });
    setClients(data || []);
    setLoading(false);
  };

  useEffect(() => { loadClients(); }, []);

  /* ── Ajouter un client ── */
  const addClient = async () => {
    if (!newEmail) return;
    const { error } = await supabase.from("clients").insert({
      email: newEmail.trim().toLowerCase(),
      full_name: newName.trim() || null,
    });
    if (error) { showToast(error.message, "err"); return; }
    showToast(`✓ ${newEmail} ajouté !`);
    setNewEmail(""); setNewName(""); setShowAdd(false);
    loadClients();
  };

  /* ── Supprimer un client ── */
  const deleteClient = async (id, email) => {
    if (!window.confirm(`Supprimer ${email} ? Toutes ses données seront perdues.`)) return;
    await supabase.from("clients").delete().eq("id", id);
    showToast("Client supprimé");
    loadClients();
  };

  /* ── Uploader un programme ── */
  const uploadProgramme = async (client, file) => {
    setUploading(true);
    try {
      const html = await file.text();
      // Extraire le nom du programme
      const m = html.match(/id="prog-name"[^>]*value="([^"]*)"/);
      const progName = m ? m[1] : file.name.replace(".html", "");

      // Désactiver l'ancien programme
      await supabase.from("programmes")
        .update({ is_active: false })
        .eq("client_id", client.id);

      // Uploader le nouveau
      const { error } = await supabase.from("programmes").insert({
        client_id:    client.id,
        html_content: html,
        programme_name: progName || "Programme",
        is_active:    true,
        uploaded_by:  (await supabase.auth.getUser()).data.user?.email,
      });

      if (error) throw error;
      showToast(`✓ Programme uploadé pour ${client.full_name || client.email}`);
      loadClients();
    } catch (e) {
      showToast(e.message, "err");
    } finally {
      setUploading(false);
      setSelected(null);
    }
  };

  const filtered = clients.filter(c =>
    c.email.includes(search.toLowerCase()) ||
    (c.full_name || "").toLowerCase().includes(search.toLowerCase())
  );

  const inputStyle = {
    padding: "10px 12px",
    background: "#141414",
    border: "1.5px solid rgba(255,255,255,0.08)",
    borderRadius: 8,
    color: "#f5f5f5",
    fontFamily: "'Inter',sans-serif",
    fontSize: 13,
    outline: "none",
    width: "100%",
    boxSizing: "border-box",
  };

  return (
    <div style={{
      minHeight: "100vh", background: "#0d0d0d",
      fontFamily: "'Inter',sans-serif", color: "#f5f5f5",
    }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;600;700;800&family=JetBrains+Mono:wght@400;500&display=swap');
        @keyframes slideDown { from{opacity:0;transform:translateY(-8px)} to{opacity:1;transform:translateY(0)} }
        .client-row:hover { background: #1a1a1a !important; }
        .upload-btn:hover { border-color: rgba(34,197,94,0.5) !important; color: #22c55e !important; }
        .del-btn:hover { color: #ef4444 !important; }
        .focus-green:focus { border-color: #22c55e !important; }
      `}</style>

      {/* Toast */}
      {toast && (
        <div style={{
          position: "fixed", top: 16, left: "50%", transform: "translateX(-50%)",
          background: toast.type === "err" ? "#1a0a0a" : "#0a1a0f",
          border: `1px solid ${toast.type === "err" ? "rgba(239,68,68,0.3)" : "rgba(34,197,94,0.3)"}`,
          borderRadius: 10, padding: "10px 18px",
          fontSize: 12, fontWeight: 600,
          color: toast.type === "err" ? "#ef4444" : GREEN,
          zIndex: 1000, animation: "slideDown 0.2s ease",
          boxShadow: "0 8px 32px rgba(0,0,0,0.5)",
          whiteSpace: "nowrap",
        }}>
          {toast.msg}
        </div>
      )}

      {/* Input file caché */}
      <input
        ref={fileRef} type="file" accept=".html"
        style={{ display: "none" }}
        onChange={e => {
          const f = e.target.files?.[0];
          if (f && selected) { uploadProgramme(selected, f); e.target.value = ""; }
        }}
      />

      {/* Header */}
      <div style={{
        background: "#0d0d0d", borderBottom: "1px solid rgba(255,255,255,0.07)",
        padding: "0 24px", height: 60,
        display: "flex", alignItems: "center", justifyContent: "space-between",
        position: "sticky", top: 0, zIndex: 100, backdropFilter: "blur(20px)",
      }}>
        <div style={{ display: "flex", alignItems: "center", gap: 10 }}>
          <div style={{ width: 30, height: 30, border: "1px solid rgba(255,255,255,0.1)", borderRadius: 7, overflow: "hidden" }}>
            <img src={LOGO_B64} alt="" style={{ width: "100%", height: "100%", objectFit: "contain" }} />
          </div>
          <div>
            <div style={{ fontSize: 13, fontWeight: 700, color: "#f5f5f5" }}>
              RB <span style={{ color: GREEN }}>Performance</span>
              <span style={{ fontSize: 10, fontWeight: 600, color: "#444", marginLeft: 8, letterSpacing: "1px" }}>COACH</span>
            </div>
          </div>
        </div>
        <button onClick={onExit} style={{
          background: "none", border: "1px solid rgba(255,255,255,0.08)",
          borderRadius: 7, padding: "5px 12px", color: "#555",
          fontSize: 11, fontWeight: 600, cursor: "pointer",
        }}>
          ← Mon app
        </button>
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "28px 20px 60px" }}>

        {/* Stats */}
        <div style={{ display: "grid", gridTemplateColumns: "repeat(3,1fr)", gap: 10, marginBottom: 24 }}>
          {[
            { label: "Clients", val: clients.length },
            { label: "Programmes actifs", val: clients.filter(c => c.programmes?.some(p => p.is_active)).length },
            { label: "Sans programme", val: clients.filter(c => !c.programmes?.some(p => p.is_active)).length },
          ].map((s, i) => (
            <div key={i} style={{
              background: "#141414", border: "1px solid rgba(255,255,255,0.06)",
              borderRadius: 12, padding: "14px 12px",
            }}>
              <div style={{ fontFamily: "'JetBrains Mono',monospace", fontSize: 22, fontWeight: 700, color: i === 2 && s.val > 0 ? "#f97316" : GREEN, lineHeight: 1 }}>{s.val}</div>
              <div style={{ fontSize: 10, color: "#555", marginTop: 3 }}>{s.label}</div>
            </div>
          ))}
        </div>

        {/* Actions */}
        <div style={{ display: "flex", gap: 10, marginBottom: 20, alignItems: "center" }}>
          <input
            className="focus-green"
            placeholder="🔍  Rechercher un client..."
            value={search}
            onChange={e => setSearch(e.target.value)}
            style={{ ...inputStyle, flex: 1, fontSize: 13 }}
          />
          <button onClick={() => setShowAdd(v => !v)} style={{
            flexShrink: 0, display: "flex", alignItems: "center", gap: 6,
            padding: "10px 16px",
            background: showAdd ? "rgba(34,197,94,0.15)" : GREEN,
            border: "none", borderRadius: 8,
            color: showAdd ? GREEN : "#0d0d0d",
            fontSize: 12, fontWeight: 700, cursor: "pointer",
          }}>
            {showAdd ? "✕ Annuler" : "＋ Nouveau client"}
          </button>
        </div>

        {/* Formulaire nouveau client */}
        {showAdd && (
          <div style={{
            background: "#141414", border: "1px solid rgba(34,197,94,0.2)",
            borderRadius: 12, padding: "16px", marginBottom: 20,
            animation: "slideDown 0.2s ease",
            display: "flex", flexDirection: "column", gap: 10,
          }}>
            <div style={{ fontSize: 10, fontWeight: 700, letterSpacing: "1.5px", textTransform: "uppercase", color: GREEN }}>
              Nouveau client
            </div>
            <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: 10 }}>
              <div>
                <label style={{ fontSize: 9, color: "#555", fontWeight: 700, letterSpacing: "1px", textTransform: "uppercase", display: "block", marginBottom: 4 }}>Email *</label>
                <input className="focus-green" type="email" placeholder="client@email.com"
                  value={newEmail} onChange={e => setNewEmail(e.target.value)}
                  style={inputStyle} />
              </div>
              <div>
                <label style={{ fontSize: 9, color: "#555", fontWeight: 700, letterSpacing: "1px", textTransform: "uppercase", display: "block", marginBottom: 4 }}>Prénom Nom</label>
                <input className="focus-green" type="text" placeholder="Thomas Dupont"
                  value={newName} onChange={e => setNewName(e.target.value)}
                  style={inputStyle} />
              </div>
            </div>
            <button onClick={addClient} disabled={!newEmail} style={{
              padding: "10px", background: newEmail ? GREEN : "#1e1e1e",
              border: "none", borderRadius: 8,
              color: newEmail ? "#0d0d0d" : "#444",
              fontSize: 12, fontWeight: 700,
              cursor: newEmail ? "pointer" : "not-allowed",
            }}>
              Créer le compte client
            </button>
          </div>
        )}

        {/* Liste clients */}
        {loading ? (
          <div style={{ textAlign: "center", padding: 40, color: "#555" }}>Chargement...</div>
        ) : filtered.length === 0 ? (
          <div style={{ textAlign: "center", padding: 40, color: "#444", fontSize: 13 }}>
            {search ? "Aucun client trouvé" : "Aucun client — ajoute ton premier client 👆"}
          </div>
        ) : (
          <div style={{ display: "flex", flexDirection: "column", gap: 6 }}>
            {filtered.map(client => {
              const activeProg = client.programmes?.find(p => p.is_active);
              const hasProg = !!activeProg;
              return (
                <div key={client.id} className="client-row" style={{
                  background: "#141414",
                  border: "1px solid rgba(255,255,255,0.06)",
                  borderRadius: 12, padding: "14px 16px",
                  display: "flex", alignItems: "center", gap: 14,
                  transition: "background 0.15s",
                }}>
                  {/* Avatar */}
                  <div style={{
                    width: 38, height: 38, borderRadius: "50%", flexShrink: 0,
                    background: hasProg ? "rgba(34,197,94,0.1)" : "rgba(255,255,255,0.04)",
                    border: `1.5px solid ${hasProg ? "rgba(34,197,94,0.25)" : "rgba(255,255,255,0.08)"}`,
                    display: "flex", alignItems: "center", justifyContent: "center",
                    fontWeight: 700, fontSize: 14,
                    color: hasProg ? GREEN : "#555",
                  }}>
                    {(client.full_name || client.email)[0].toUpperCase()}
                  </div>

                  {/* Infos */}
                  <div style={{ flex: 1, minWidth: 0 }}>
                    <div style={{ fontSize: 13, fontWeight: 600, color: "#f5f5f5", marginBottom: 2 }}>
                      {client.full_name || <span style={{ color: "#555" }}>—</span>}
                    </div>
                    <div style={{ fontSize: 11, color: "#555" }}>{client.email}</div>
                    {hasProg && (
                      <div style={{ fontSize: 10, color: GREEN, marginTop: 2, display: "flex", alignItems: "center", gap: 5 }}>
                        <span style={{ width: 5, height: 5, borderRadius: "50%", background: GREEN, display: "inline-block" }} />
                        {activeProg.programme_name} · {new Date(activeProg.uploaded_at).toLocaleDateString("fr-FR", { day: "2-digit", month: "short" })}
                      </div>
                    )}
                    {!hasProg && (
                      <div style={{ fontSize: 10, color: "#f97316", marginTop: 2 }}>⚠ Aucun programme</div>
                    )}
                  </div>

                  {/* Actions */}
                  <div style={{ display: "flex", alignItems: "center", gap: 6, flexShrink: 0 }}>
                    <button
                      className="upload-btn"
                      disabled={uploading}
                      onClick={() => { setSelected(client); fileRef.current?.click(); }}
                      style={{
                        display: "flex", alignItems: "center", gap: 5,
                        padding: "6px 12px",
                        background: "transparent",
                        border: "1px solid rgba(255,255,255,0.1)",
                        borderRadius: 7,
                        color: "#9ca3af",
                        fontSize: 10.5, fontWeight: 600, cursor: "pointer",
                        transition: "all 0.15s",
                      }}
                    >
                      <svg viewBox="0 0 16 16" fill="none" style={{ width: 11, height: 11 }}>
                        <path d="M8 2v8M4 6l4-4 4 4" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round" strokeLinejoin="round"/>
                        <line x1="2" y1="13" x2="14" y2="13" stroke="currentColor" strokeWidth="1.6" strokeLinecap="round"/>
                      </svg>
                      {hasProg ? "Mettre à jour" : "Upload programme"}
                    </button>
                    <button
                      className="del-btn"
                      onClick={() => deleteClient(client.id, client.email)}
                      style={{
                        background: "none", border: "none", color: "#333",
                        cursor: "pointer", fontSize: 16, padding: "4px 6px",
                        borderRadius: 5, transition: "color 0.15s",
                      }}
                    >×</button>
                  </div>
                </div>
              );
            })}
          </div>
        )}
      </div>

      {uploading && (
        <div style={{
          position: "fixed", inset: 0, background: "rgba(0,0,0,0.7)",
          backdropFilter: "blur(8px)", zIndex: 999,
          display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center", gap: 12,
        }}>
          <div style={{
            width: 48, height: 48, border: "3px solid #1a1a1a", borderTopColor: GREEN,
            borderRadius: "50%", animation: "spin 0.8s linear infinite",
          }} />
          <div style={{ color: GREEN, fontSize: 13, fontWeight: 600 }}>Upload en cours...</div>
          <style>{`@keyframes spin { to { transform: rotate(360deg); } }`}</style>
        </div>
      )}
    </div>
  );
}
